      "mangalDosh.houses.1st.name": "1st House (Lagna)",
      "mangalDosh.houses.1st.effect": "Affects personality and can cause aggressive behavior. May lead to conflicts in marriage due to dominating nature.",
      "mangalDosh.houses.2nd.name": "2nd House",
      "mangalDosh.houses.2nd.effect": "Impacts family life, wealth, and speech. May cause harsh speech leading to family disputes.",
      "mangalDosh.houses.4th.name": "4th House",
      "mangalDosh.houses.4th.effect": "Affects domestic peace, property, and relationship with mother. Can cause frequent changes in residence.",
      "mangalDosh.houses.7th.name": "7th House",
      "mangalDosh.houses.7th.effect": "Directly impacts marriage and spouse. Most severe placement causing delays, conflicts, or separation.",
      "mangalDosh.houses.8th.name": "8th House",
      "mangalDosh.houses.8th.effect": "Affects longevity, in-laws, and sudden events. Can cause health issues for spouse or accidents.",
      "mangalDosh.houses.12th.name": "12th House",
      "mangalDosh.houses.12th.effect": "Impacts bed pleasures, expenses, and foreign connections. May cause separation or excessive expenses.",
      "mangalDosh.description1": "Mangal Dosh, also known as Kuja Dosha, Bhom Dosha, or Manglik Dosha, is an astrological condition that occurs when Mars (Mangal) is placed in certain houses in a person's birth chart. It is one of the most discussed doshas in Vedic astrology, particularly concerning marriage compatibility.",
      "mangalDosh.description2": "The dosha is formed when Mars occupies the 1st, 2nd, 4th, 7th, 8th, or 12th house from the Ascendant (Lagna), Moon, or Venus in the birth chart. Mars is a fiery, aggressive planet, and its placement in these houses is believed to affect marriage, relationships, and domestic harmony.",
      "mangalDosh.cancellation.1": "Mars is in its own sign (Aries or Scorpio)",
      "mangalDosh.cancellation.2": "Mars is exalted in Capricorn",
      "mangalDosh.cancellation.3": "Mars is aspected by benefic Jupiter",
      "mangalDosh.cancellation.4": "Mars is conjunct with benefic planets (Jupiter, Venus, Mercury)",
      "mangalDosh.cancellation.5": "Both partners have Mangal Dosha (mutual cancellation)",
      "mangalDosh.cancellation.6": "Mars is in Navamsa of benefic planets",
      "mangalDosh.cancellation.7": "Person is born on Tuesday",
      "mangalDosh.cancellation.8": "Mars is in 2nd house in Gemini, Virgo, or Sagittarius",
      "mangalDosh.cancellation.9": "Mars is in 12th house in Taurus or Libra",
      "mangalDosh.cancellation.10": "Mars is in 4th house in Aries or Scorpio",
      "mangalDosh.cancellation.11": "Mars is in 7th house in Cancer or Capricorn",
      "mangalDosh.cancellation.12": "Mars is in 8th house in Sagittarius or Pisces",
      "mangalDosh.cancellation.13": "Age above 28 years (Dosha weakens significantly)",
      "mangalDosh.cancellation.14": "Mars is retrograde",
      "mangalDosh.cancellation.15": "Mars is combust (close to Sun)",
      "mangalDosh.remedies.puja.1": "Perform Mangal Shanti Puja on Tuesday",
      "mangalDosh.remedies.puja.2": "Conduct Navagraha Shanti Puja",
      "mangalDosh.remedies.puja.3": "Perform Kumbh Vivah (symbolic marriage to a pot or tree)",
      "mangalDosh.remedies.puja.4": "Visit Mangalnath Temple in Ujjain",
      "mangalDosh.remedies.puja.5": "Perform Rudrabhishek on Mondays",
      "mangalDosh.remedies.mantras.1": "Chant 'Om Angarakaya Namaha' 108 times daily",
      "mangalDosh.remedies.mantras.2": "Recite Hanuman Chalisa daily, especially on Tuesdays",
      "mangalDosh.remedies.mantras.3": "Chant Mangal Beej Mantra: 'Om Kram Kreem Kraum Sah Bhaumaya Namaha'",
      "mangalDosh.remedies.mantras.4": "Recite Sunderkand on Tuesdays and Saturdays",
      "mangalDosh.remedies.mantras.5": "Chant Gayatri Mantra 108 times daily",
      "mangalDosh.remedies.donations.1": "Donate red items (red cloth, red lentils, red flowers) on Tuesdays",
      "mangalDosh.remedies.donations.2": "Donate blood on Tuesdays (highly recommended)",
      "mangalDosh.remedies.donations.3": "Donate wheat, jaggery, and copper on Tuesdays",
      "mangalDosh.remedies.donations.4": "Feed monkeys with jaggery and gram on Tuesdays",
      "mangalDosh.remedies.donations.5": "Donate to soldiers or fire department",
      "mangalDosh.remedies.lifestyle.1": "Fast on Tuesdays (eat only once after sunset)",
      "mangalDosh.remedies.lifestyle.2": "Wear a coral (Moonga) gemstone after consultation",
      "mangalDosh.remedies.lifestyle.3": "Wear red or orange clothes on Tuesdays",
      "mangalDosh.remedies.lifestyle.4": "Serve your siblings and younger people",
