    "guides.nakshatras.title": "27 Nakshatras: Complete Guide to Vedic Lunar Mansions",
    "guides.nakshatras.subtitle": "Discover the profound wisdom of the 27 Nakshatras in Vedic astrology. Learn about each lunar constellation's characteristics, ruling deity, and influence on personality and destiny.",
    "guides.nakshatras.readTime": "20 min read",
    "guides.nakshatras.updated": "Updated: January 2025",
    "guides.nakshatras.tldr.title": "TL;DR - Quick Summary",
    "guides.nakshatras.tldr.content": "Nakshatras are 27 lunar mansions in Vedic astrology, each spanning 13°20' of the zodiac. Your birth Nakshatra (based on Moon's position) reveals your emotional nature, personality traits, and life path. Each Nakshatra has a ruling planet, deity, symbol, and unique characteristics. They're essential for marriage matching, muhurta selection, and the Vimshottari Dasha system.",
    "guides.nakshatras.findYourNakshatra": "Find Your Nakshatra",
    "guides.nakshatras.generateKundli": "Generate Kundli",
    "guides.nakshatras.sections.completeList": "Complete List of 27 Nakshatras",
    "guides.nakshatras.sections.detailedDescriptions": "Detailed Nakshatra Descriptions",
    "guides.nakshatras.sections.understandingGroups": "Understanding Nakshatra Groups",
    "guides.nakshatras.sections.faq": "Frequently Asked Questions",
    "guides.nakshatras.table.number": "#",
    "guides.nakshatras.table.nakshatra": "Nakshatra",
    "guides.nakshatras.table.degrees": "Degrees",
