    "dosha.kaalSarp.types.mahapadma.name": "Mahapadma Kaal Sarp Dosh",
    "dosha.kaalSarp.types.mahapadma.effects": "Impacts enemies, health, and expenses. Legal issues and health problems possible.",
    "dosha.kaalSarp.types.takshak.name": "Takshak Kaal Sarp Dosh",
