    "dosha.kaalSarp.types.karkotak.name": "Karkotak Kaal Sarp Dosh",
    "dosha.kaalSarp.types.karkotak.effects": "Impacts longevity, secrets, and family. Sudden events and family wealth issues.",
    "dosha.kaalSarp.types.shankhachud.name": "Shankhachud Kaal Sarp Dosh",
    "dosha.kaalSarp.types.shankhachud.effects": "Affects fortune, father, and courage. Luck fluctuations and sibling issues.",
    "dosha.kaalSarp.types.ghatak.name": "Ghatak Kaal Sarp Dosh",
