    "dosha.kaalSarp.temples.rameswaram.name": "रामेश्वरम, तमिलनाडु",
    "dosha.kaalSarp.temples.rameswaram.desc": "नाग दोष निवारण के लिए",
    "dosha.kaalSarp.temples.kukke.name": "कुक्के सुब्रमण्य, कर्नाटक",
    "dosha.kaalSarp.temples.kukke.desc": "प्रसिद्ध नाग मंदिर",
    "dosha.kaalSarp.temples.thirunageswaram.name": "तिरुनागेश्वरम, तमिलनाडु",
    "dosha.kaalSarp.temples.thirunageswaram.desc": "राहु मंदिर",
    "dosha.kaalSarp.kundliDesc": "काल सर्प दोष की जांच के लिए अपनी जन्म कुंडली बनाएं।",
    "dosha.kaalSarp.understanding.title": "संदर्भ में काल सर्प दोष को समझना",
    "dosha.kaalSarp.understanding.para1": "जबकि वैदिक ज्योतिष में काल सर्प दोष को महत्वपूर्ण माना जाता है, यह समझना महत्वपूर्ण है कि इसके प्रभाव कई कारकों से संशोधित होते हैं। व्यक्तिगत ग्रहों की शक्ति, लाभकारी पहलू और समग्र चार्ट विन्यास सभी एक भूमिका निभाते हैं।",
    "dosha.kaalSarp.understanding.para2": "कई सफल लोगों की कुंडली में काल सर्प योग होता है। यह योग तीव्र ध्यान, दृढ़ संकल्प और बाधाओं को पार करने की क्षमता भी ला सकता है। यह अक्सर एक ऐसी आत्मा को इंगित करता है जिसने आध्यात्मिक विकास के लिए चुनौतीपूर्ण पाठ चुने हैं।",
    "dosha.kaalSarp.understanding.para3": "इस योग से डरने के बजाय, इसे परिवर्तन के अवसर के रूप में देखें। उपाय ऊर्जाओं को संतुलित करने और चुनौतीपूर्ण प्रभावों को कम करने में मदद करते हैं जबकि इस शक्तिशाली विन्यास की सकारात्मक क्षमता को बढ़ाते हैं।",
    "calculator.fullKundliAnalysis": "पूर्ण कुंडली विश्लेषण",
    "calculator.generateKundli": "कुंडली बनाएं",
    "consultation.consultAstrologer": "ज्योतिषी से परामर्श करें",
    "consultation.personalizedGuidance": "विशेषज्ञों से व्यक्तिगत मार्गदर्शन प्राप्त करें।",
    "consultation.bookConsultation": "परामर्श बुक करें",
    "doshas.mangalDosh.houses.1st.name": "प्रथम भाव (लग्न)",
    "doshas.mangalDosh.houses.1st.effect": "व्यक्तित्व को प्रभावित करता है और आक्रामक व्यवहार का कारण बन सकता है। प्रभुत्वशाली स्वभाव के कारण विवाह में संघर्ष हो सकता है।",
    "doshas.mangalDosh.houses.2nd.name": "द्वितीय भाव",
    "doshas.mangalDosh.houses.2nd.effect": "पारिवारिक जीवन, धन और वाणी को प्रभावित करता है। कठोर वाणी के कारण पारिवारिक विवाद हो सकते हैं।",
    "doshas.mangalDosh.houses.4th.name": "चतुर्थ भाव",
    "doshas.mangalDosh.houses.4th.effect": "घरेलू शांति, संपत्ति और माता के साथ संबंध को प्रभावित करता है। निवास में बार-बार बदलाव हो सकता है।",
    "doshas.mangalDosh.houses.7th.name": "सप्तम भाव",
    "doshas.mangalDosh.houses.7th.effect": "सीधे विवाह और जीवनसाथी को प्रभावित करता है। सबसे गंभीर स्थिति जो देरी, संघर्ष या अलगाव का कारण बनती है।",
    "doshas.mangalDosh.houses.8th.name": "अष्टम भाव",
    "doshas.mangalDosh.houses.8th.effect": "दीर्घायु, ससुराल और अचानक घटनाओं को प्रभावित करता है। जीवनसाथी के लिए स्वास्थ्य समस्याएं या दुर्घटनाएं हो सकती हैं।",
    "doshas.mangalDosh.houses.12th.name": "द्वादश भाव",
    "doshas.mangalDosh.houses.12th.effect": "शय्या सुख, खर्च और विदेशी संबंधों को प्रभावित करता है। अलगाव या अत्यधिक खर्च हो सकता है।",
    "doshas.severity.mild": "हल्का",
    "doshas.severity.moderate": "मध्यम",
    "doshas.severity.severe": "गंभीर",
