    "aiAstrologer.chat.placeholder": "உங்கள் ஜாதகம், கோள் நிலை, தோஷங்கள் பற்றி கேளுங்கள்...",
    "aiAstrologer.features.planetaryAnalysis.title": "கிரக பகுப்பாய்வு",
    "aiAstrologer.features.planetaryAnalysis.description": "கிரக நிலைகள், கோள் நிலை மற்றும் உங்கள் வாழ்க்கையில் அவற்றின் விளைவுகள் பற்றிய நுண்ணறிவுகளைப் பெறுங்கள்।",
    "aiAstrologer.features.doshaRemedies.title": "தோஷ பரிகாரங்கள்",
    "aiAstrologer.features.doshaRemedies.description": "மங்கள், கால சர்ப், சாடே சாதி போன்ற தோஷங்கள் மற்றும் அவற்றின் சக்திவாய்ந்த பரிகாரங்களைப் பற்றி அறியுங்கள்.",
    "aiAstrologer.features.lifeGuidance.title": "வாழ்க்கை வழிகாட்டுதல்",
    "aiAstrologer.features.lifeGuidance.description": "தொழில், உறவுகள், ஆரோக்கியம் மற்றும் ஆன்மீக வளர்ச்சி குறித்த வழிகாட்டுதலைப் பெறுங்கள்.",
    "aiAstrologer.disclaimer.note": "குறிப்பு:",
    "aiAstrologer.disclaimer.text": "AI ஜோதிடர் வேத ஜோதிட கோட்பாடுகளின் அடிப்படையில் பொதுவான வழிகாட்டுதலை வழங்குகிறது. உங்கள் சரியான ஜாதகத்தின் அடிப்படையில் தனிப்பயனாக்கப்பட்ட கணிப்புகளுக்கு, தயவுசெய்து",
    "aiAstrologer.disclaimer.consultLink": "எங்கள் நிபுணர் ஜோதிடர்களுடன் ஆலோசிக்கவும்",
    "aiAstrologer.questions.moonSign": "என் சந்திர ராசி என் உணர்வுகளைப் பற்றி என்ன சொல்கிறது?",
    "aiAstrologer.questions.saturnTransit": "2026 இல் சனி கோள் நிலை என் தொழிலை எவ்வாறு பாதிக்கும்?",
    "aiAstrologer.questions.mangalRemedies": "மங்கள் தோஷத்திற்கான பரிகாரங்கள் என்ன?",
    "aiAstrologer.questions.marriageTime": "ஜோதிடத்தின் படி இது திருமணத்திற்கு நல்ல நேரமா?",
