      navamsa: { title: "નવાંશ અને વિભાગીય ચાર્ટ", subtitle: "તમારો નવાંશ (D-9) અને અન્ય વિભાગીય ચાર્ટ (વર્ગ) ગણો. આ ચાર્ટ લગ્ન, કારકિર્દી, સંતાન અને શિક્ષણ જેવા ચોક્કસ જીવન ક્ષેત્રો વિશે ઊંડી સમજ આપે છે.", generate: "નવાંશ બનાવો", calculateCharts: "ચાર્ટ ગણો", birthTimeNote: "વિભાગીય ચાર્ટ ગણતરી માટે સચોટ જન્મ સમય જરૂરી છે", timeWarning: "થોડી મિનિટોનો તફાવત પણ વિભાગીય ચાર્ટ સ્થાનો બદલી શકે છે", whyImportant: "નવાંશ શા માટે મહત્વપૂર્ણ છે", whyImportantDesc: "નવાંશ ચાર્ટ (D-9) જન્મ ચાર્ટ પછી બીજો સૌથી મહત્વપૂર્ણ ચાર્ટ માનવામાં આવે છે. તે ગ્રહોની સાચી શક્તિ દર્શાવે છે અને લગ્ન ભવિષ્યવાણી, જીવનસાથીની લાક્ષણિકતાઓ સમજવા અને આધ્યાત્મિક વિકાસ મૂલ્યાંકન માટે આવશ્યક છે.", divisionalCharts: "વિભાગીય ચાર્ટ", resultPlaceholderDesc: "ઊંડી જ્યોતિષ સમજ માટે તમારો નવાંશ અને અન્ય વિભાગીય ચાર્ટ ગણવા માટે ફોર્મ ભરો.", planet: "ગ્રહ", sign: "રાશિ", sanskrit: "સંસ્કૃત", d9Chart: "D-9 નવાંશ ચાર્ટ", d1Chart: "D-1 જન્મકુંડળી", comparison: "ચાર્ટ સરખામણી", vargottama: "વર્ગોત્તમ ગ્રહો", pushkara: "પુષ્કર નવાંશ", marriageAnalysis: "લગ્ન વિશ્લેષણ", spiritualPath: "આધ્યાત્મિક માર્ગ", rashiChart: "રાશિ ચાર્ટ (D-1)", rashiChartDesc: "કુલ જીવન પેટર્ન અને વ્યક્તિત્વ દર્શાવતો મુખ્ય જન્મ ચાર્ટ", navamsaChart: "નવાંશ ચાર્ટ (D-9)", navamsaChartDesc: "લગ્ન, જીવનસાથી, ધર્મ અને આધ્યાત્મિક માર્ગ. સૌથી મહત્વપૂર્ણ વિભાગીય ચાર્ટ.", dasamsaChart: "દશાંશ ચાર્ટ (D-10)", dasamsaChartDesc: "કારકિર્દી, વ્યવસાય, પ્રતિષ્ઠા અને સમાજમાં સફળતા", saptamsaChart: "સપ્તાંશ ચાર્ટ (D-7)", saptamsaChartDesc: "સંતાન, સંતાન અને સર્જનાત્મક ક્ષમતા", dwadasamsaChart: "દ્વાદશાંશ ચાર્ટ (D-12)", dwadasamsaChartDesc: "માતાપિતા, પૂર્વજો અને કર્મિક વારસો", chaturvimsamsaChart: "ચતુર્વિંશાંશ ચાર્ટ (D-24)", chaturvimsamsaChartDesc: "શિક્ષણ, શીખવું અને શૈક્ષણિક સફળતા" },
      yoga: { title: "યોગ કેલ્ક્યુલેટર", subtitle: "તમારા ચાર્ટમાં યોગ શોધો.", calculate: "યોગ શોધો", detectYogas: "યોગ શોધો", yogasFound: "મળેલા યોગ", noYogasFound: "કોઈ મુખ્ય યોગ મળ્યા નથી", noYogasMessage: "તમારા ચાર્ટમાં કોઈ મુખ્ય યોગ મળ્યા નથી. આનો અર્થ એ નથી કે તમારા ચાર્ટમાં ક્ષમતા નથી - વ્યક્તિગત ગ્રહ શક્તિઓ અને ભાવ સ્થાન પણ મહત્વની ભૂમિકા ભજવે છે.", whatAre: "યોગ શું છે?", whatAreDesc: "યોગ એ વિશેષ ગ્રહ સંયોગો છે જે અસાધારણ ગુણો અથવા જીવનની ઘટનાઓ દર્શાવે છે. તેઓ સંપત્તિ (ધન યોગ), શક્તિ (રાજ યોગ), જ્ઞાન (હંસ યોગ) અને વધુ દર્શાવી શકે છે. મજબૂત યોગોની હાજરી જીવનના પરિણામોને નોંધપાત્ર રીતે સુધારી શકે છે.", birthDetailsNote: "તમારા ચાર્ટમાં યોગ શોધવા માટે સચોટ જન્મ માહિતી આપો", summary: "યોગ સારાંશ", detectedYogas: "મળેલા યોગ", detectedYogasDesc: "તમારા જન્મ ચાર્ટમાં મળેલા ગ્રહ સંયોગો", resultPlaceholderDesc: "તમારા જન્મ ચાર્ટમાં શક્તિશાળી યોગ (ગ્રહ સંયોગો) શોધવા માટે ફોર્મ ભરો.", rajYoga: "રાજ યોગ", rajYogaDesc: "કેન્દ્ર અને ત્રિકોણ અધિપતિઓના સંયોગથી રચાય છે. શક્તિ, સત્તા અને જીવનમાં અગ્રણી પદો પર ઉન્નતિ દર્શાવે છે.", dhanaYoga: "ધન યોગ", dhanaYogaDesc: "બીજા અને અગિયારમા ભાવ અધિપતિઓ સાથે સંકળાયેલ સંપત્તિ-ઉત્પાદક સંયોગો. આર્થિક સમૃદ્ધિ અને ભૌતિક વિપુલતા દર્શાવે છે.", panchMahapurusha: "પંચ મહાપુરુષ", panchMahapurushaDesc: "મંગળ, બુધ, ગુરુ, શુક્ર અથવા શનિ કેન્દ્રમાં તેમની પોતાની અથવા ઉચ્ચ રાશિમાં હોય ત્યારે રચાતા પાંચ મહાન વ્યક્તિ યોગ.", gajkesariYoga: "ગજકેસરી યોગ", budhaAdityaYoga: "બુધાદિત્ય યોગ", malavyaYoga: "માલવ્ય યોગ", hamsa: "હંસ યોગ", ruchaka: "રુચક યોગ", bhadra: "ભદ્ર યોગ", shasha: "શશ યોગ", yogaStrength: "યોગ શક્તિ", strength: "શક્તિ", planetsInvolved: "સંકળાયેલા ગ્રહો", effects: "પ્રભાવ", activationPeriod: "સક્રિય સમયગાળો" },
