      transit: { title: "ಗೋಚರ ವಿಶ್ಲೇಷಣೆ", subtitle: "ಪ್ರಸ್ತುತ ಗ್ರಹ ಗೋಚರಗಳು ನಿಮ್ಮ ಜನ್ಮ ಚಾರ್ಟ್ ಮೇಲೆ ಹೇಗೆ ಪ್ರಭಾವ ಬೀರುತ್ತವೆ ಎಂಬುದನ್ನು ವಿಶ್ಲೇಷಿಸಿ. ಗ್ರಹಗಳು ರಾಶಿಚಕ್ರದಲ್ಲಿ ಚಲಿಸುವಾಗ ಪ್ರಮುಖ ಜೀವನ ಘಟನೆಗಳು ಮತ್ತು ಅವಧಿಗಳನ್ನು ಅರ್ಥಮಾಡಿಕೊಳ್ಳಿ.", analyze: "ಗೋಚರ ವಿಶ್ಲೇಷಿಸಿ", analyzeTransits: "ಗೋಚರ ವಿಶ್ಲೇಷಿಸಿ", birthChartNote: "ವೈಯಕ್ತಿಕ ಗೋಚರ ವಿಶ್ಲೇಷಣೆಗಾಗಿ ನಿಮ್ಮ ಜನ್ಮ ವಿವರಗಳನ್ನು ಒದಗಿಸಿ", whatAre: "ಗೋಚರಗಳು ಎಂದರೇನು?", whatAreDesc: "ಗೋಚರಗಳು ಆಕಾಶದಲ್ಲಿ ಗ್ರಹಗಳ ಪ್ರಸ್ತುತ ಸ್ಥಾನಗಳು ಮತ್ತು ಅವು ನಿಮ್ಮ ಜನ್ಮ ಚಾರ್ಟ್‌ನೊಂದಿಗೆ ಹೇಗೆ ಸಂವಹನ ನಡೆಸುತ್ತವೆ ಎಂಬುದನ್ನು ಸೂಚಿಸುತ್ತವೆ. ಶನಿ, ಗುರು, ರಾಹು ಮತ್ತು ಕೇತುವಿನ ಪ್ರಮುಖ ಗೋಚರಗಳು ಜೀವನದಲ್ಲಿ ಗಮನಾರ್ಹ ಘಟನೆಗಳು ಮತ್ತು ಬದಲಾವಣೆಗಳನ್ನು ತರಬಹುದು.", currentTransits: "ಪ್ರಸ್ತುತ ಗೋಚರಗಳು", transitEffects: "ಗೋಚರ ಪ್ರಭಾವಗಳು", resultPlaceholderDesc: "ಪ್ರಸ್ತುತ ಗ್ರಹ ಗೋಚರಗಳು ನಿಮ್ಮ ಜೀವನವನ್ನು ಹೇಗೆ ಪ್ರಭಾವಿಸುತ್ತವೆ ಎಂಬುದನ್ನು ನೋಡಲು ನಿಮ್ಮ ಜನ್ಮ ವಿವರಗಳನ್ನು ನಮೂದಿಸಿ.", planet: "ಗ್ರಹ", currentSign: "ಪ್ರಸ್ತುತ ರಾಶಿ", natalSign: "ಜನ್ಮ ರಾಶಿ", transitingOver: "ಗೋಚರಿಸುತ್ತಿದೆ", houseFrom: "ಭಾವದಿಂದ", aspect: "ದೃಷ್ಟಿ", effect: "ಪ್ರಭಾವ", duration: "ಅವಧಿ", favorable: "ಅನುಕೂಲ", unfavorable: "ಪ್ರತಿಕೂಲ", neutral: "ತಟಸ್ಥ", mixed: "ಮಿಶ್ರ", majorTransits: "ಪ್ರಮುಖ ಗೋಚರಗಳು", saturnTransit: "ಶನಿ ಗೋಚರ", jupiterTransit: "ಗುರು ಗೋಚರ", rahuKetuTransit: "ರಾಹು-ಕೇತು ಗೋಚರ", marsTransit: "ಮಂಗಳ ಗೋಚರ", venusTransit: "ಶುಕ್ರ ಗೋಚರ", mercuryTransit: "ಬುಧ ಗೋಚರ", sunTransit: "ಸೂರ್ಯ ಗೋಚರ", moonTransit: "ಚಂದ್ರ ಗೋಚರ", transitStart: "ಗೋಚರ ಪ್ರಾರಂಭ", transitEnd: "ಗೋಚರ ಅಂತ್ಯ", overallEffect: "ಒಟ್ಟಾರೆ ಪ್ರಭಾವ", areasAffected: "ಪ್ರಭಾವಿತ ಕ್ಷೇತ್ರಗಳು", recommendations: "ಶಿಫಾರಸುಗಳು" , asOf: "ದಿನಾಂಕ", thFromMoon: "ನೇ ಚಂದ್ರನಿಂದ"},
