      transit: { title: "ഗോചര വിശകലനം", subtitle: "നിലവിലെ ഗ്രഹ ഗോചരങ്ങൾ നിങ്ങളുടെ ജനന ചാർട്ടിനെ എങ്ങനെ ബാധിക്കുന്നുവെന്ന് വിശകലനം ചെയ്യുക. ഗ്രഹങ്ങൾ രാശിചക്രത്തിലൂടെ നീങ്ങുമ്പോൾ പ്രധാന ജീവിത സംഭവങ്ങളും കാലഘട്ടങ്ങളും മനസ്സിലാക്കുക.", analyze: "ഗോചരം വിശകലനം ചെയ്യുക", analyzeTransits: "ഗോചരങ്ങൾ വിശകലനം ചെയ്യുക", birthChartNote: "വ്യക്തിഗത ഗോചര വിശകലനത്തിനായി നിങ്ങളുടെ ജനന വിവരങ്ങൾ നൽകുക", whatAre: "ഗോചരങ്ങൾ എന്താണ്?", whatAreDesc: "ഗോചരങ്ങൾ ആകാശത്തിലെ ഗ്രഹങ്ങളുടെ നിലവിലെ സ്ഥാനങ്ങളും അവ നിങ്ങളുടെ ജനന ചാർട്ടുമായി എങ്ങനെ ഇടപഴകുന്നുവെന്നും സൂചിപ്പിക്കുന്നു. ശനി, വ്യാഴം, രാഹു, കേതു എന്നിവയുടെ പ്രധാന ഗോചരങ്ങൾ ജീവിതത്തിൽ പ്രധാന സംഭവങ്ങളും മാറ്റങ്ങളും കൊണ്ടുവരും.", currentTransits: "നിലവിലെ ഗോചരങ്ങൾ", transitEffects: "ഗോചര ഫലങ്ങൾ", resultPlaceholderDesc: "നിലവിലെ ഗ്രഹ ഗോചരങ്ങൾ നിങ്ങളുടെ ജീവിതത്തെ എങ്ങനെ ബാധിക്കുന്നുവെന്ന് കാണാൻ നിങ്ങളുടെ ജനന വിവരങ്ങൾ നൽകുക.", planet: "ഗ്രഹം", currentSign: "നിലവിലെ രാശി", natalSign: "ജന്മ രാശി", transitingOver: "ഗോചരിക്കുന്നു", houseFrom: "ഭാവത്തിൽ നിന്ന്", aspect: "ദൃഷ്ടി", effect: "ഫലം", duration: "കാലാവധി", favorable: "അനുകൂലം", unfavorable: "പ്രതികൂലം", neutral: "നിഷ്പക്ഷം", mixed: "മിശ്രം", majorTransits: "പ്രധാന ഗോചരങ്ങൾ", saturnTransit: "ശനി ഗോചരം", jupiterTransit: "വ്യാഴ ഗോചരം", rahuKetuTransit: "രാഹു-കേതു ഗോചരം", marsTransit: "ചൊവ്വ ഗോചരം", venusTransit: "ശുക്ര ഗോചരം", mercuryTransit: "ബുധ ഗോചരം", sunTransit: "സൂര്യ ഗോചരം", moonTransit: "ചന്ദ്ര ഗോചരം", transitStart: "ഗോചര ആരംഭം", transitEnd: "ഗോചര അവസാനം", overallEffect: "മൊത്തത്തിലുള്ള ഫലം", areasAffected: "ബാധിക്കപ്പെട്ട മേഖലകൾ", recommendations: "ശുപാർശകൾ" , asOf: "തീയതി", thFromMoon: "ാം ചന്ദ്രനിൽ നിന്ന്"},
